'use client';

import { useEffect, useState } from 'react';
import axios from 'axios';
import Link from 'next/link';

interface Task {
  _id: string;
  title: string;
  dueDate: string;
}

export default function Dashboard() {
  const [createdTasks, setCreatedTasks] = useState<Task[]>([]);
  const [assignedTasks, setAssignedTasks] = useState<Task[]>([]);
  const [overdueTasks, setOverdueTasks] = useState<Task[]>([]);

  useEffect(() => {
  const userId = localStorage.getItem('userId'); // or get it from auth context
  axios
    .post('http://localhost:5100/dashboard', { userId })
    .then((res) => {
      setCreatedTasks(res.data.created);
      setAssignedTasks(res.data.assigned);
      setOverdueTasks(res.data.overdue);
    })
    .catch((err) => console.error('Error fetching dashboard:', err));
}, []);


  return (
    <div className="p-4">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold">Dashboard</h1>
        <div className="space-x-4">
          <Link href="/tasks">
            <span className="text-blue-600 hover:underline">View All Tasks</span>
          </Link>
          <Link href="/tasks#create">
            <span className="text-blue-600 hover:underline">Create Task</span>
          </Link>
        </div>
      </div>

      <section className="mb-6">
        <h2 className="text-xl font-semibold mb-2">Tasks Assigned to Me</h2>
        {assignedTasks.map((task) => (
          <div key={task._id}>{task.title}</div>
        ))}
      </section>

      <section className="mb-6">
        <h2 className="text-xl font-semibold mb-2">Tasks I Created</h2>
        {createdTasks.map((task) => (
          <div key={task._id}>{task.title}</div>
        ))}
      </section>

      <section>
        <h2 className="text-xl font-semibold mb-2">Overdue Tasks</h2>
        {overdueTasks.map((task) => (
          <div key={task._id}>{task.title}</div>
        ))}
      </section>
    </div>
  );
}
